-- Source: Ministry of Civil Affairs of the People's Republic of China
-- Dataset: 2023 county-level and above administrative division codes
-- Source URL: https://www.mca.gov.cn/mzsj/xzqh/2023/202301xzqh.html

ALTER TABLE region_area ADD COLUMN area_code VARCHAR(12) NULL AFTER name;
ALTER TABLE region_area MODIFY COLUMN level VARCHAR(255) COMMENT '地区层级：province/city/district';
ALTER TABLE region_area MODIFY COLUMN name VARCHAR(255) COMMENT '地区名称';
ALTER TABLE region_area MODIFY COLUMN area_code VARCHAR(12) COMMENT '行政区划代码';
ALTER TABLE region_area MODIFY COLUMN parent_id BIGINT COMMENT '上级地区 ID';
ALTER TABLE region_area MODIFY COLUMN sort_order INT COMMENT '展示排序';
DELETE FROM region_area;
ALTER TABLE region_area AUTO_INCREMENT = 1;




CREATE UNIQUE INDEX uk_region_area_code ON region_area (area_code);
CREATE INDEX idx_region_area_parent_id ON region_area (parent_id);
